type RateLimitStore = Map<string, { count: number; expires: number }>;

// Use global to persist across hot reloads in development
const globalStore = global as unknown as { rateLimitStore?: RateLimitStore };
const store: RateLimitStore = globalStore.rateLimitStore || new Map();
if (process.env.NODE_ENV !== "production") globalStore.rateLimitStore = store;

interface RateLimitOptions {
  interval: number; // milliseconds
  limit: number; // max requests
}

export function rateLimit(ip: string, options: RateLimitOptions): boolean {
  const now = Date.now();
  const record = store.get(ip);

  if (!record) {
    store.set(ip, { count: 1, expires: now + options.interval });
    return true;
  }

  if (now > record.expires) {
    store.set(ip, { count: 1, expires: now + options.interval });
    return true;
  }

  if (record.count >= options.limit) {
    return false;
  }

  record.count += 1;
  return true;
}
